import { type } from "arktype";

// State is a discriminated union over the "status" literal field.
// Each branch has a distinct status literal so ArkType can deterministically resolve them.
export const State = type(
  { status: "'idle'" },
  "|",
  { status: "'loading'", startedAt: "number >= 0" },
  "|",
  { status: "'success'", data: "unknown", fetchedAt: "number >= 0" },
  "|",
  { status: "'failure'", code: "400 <= number <= 599", reason: "1 <= string <= 200" }
);

// Event is a discriminated union over the "type" literal field.
export const Event = type(
  { type: "'start'", at: "number" },
  "|",
  { type: "'resolve'", data: "unknown", at: "number" },
  "|",
  { type: "'reject'", code: "number", reason: "string", at: "number" },
  "|",
  { type: "'reset'" }
);

export type State = typeof State.infer;
export type Event = typeof Event.infer;

import { type } from "arktype";
import { State, Event } from "./state.js";
import type { State as StateType, Event as EventType } from "./state.js";

// The raw transition logic - implements the transition rules.
// This function assumes inputs are already validated.
function rawTransition(state: StateType, event: EventType): StateType {
  // Reset rule: any state + Reset -> Idle
  if (event.type === "reset") {
    return { status: "idle" };
  }

  // Idle + Start -> Loading
  if (state.status === "idle" && event.type === "start") {
    return { status: "loading", startedAt: Math.trunc(event.at) };
  }

  // Loading + Resolve -> Success
  if (state.status === "loading" && event.type === "resolve") {
    return {
      status: "success",
      data: event.data,
      fetchedAt: Math.trunc(event.at),
    };
  }

  // Loading + Reject -> Failure
  if (state.status === "loading" && event.type === "reject") {
    return {
      status: "failure",
      code: event.code,
      reason: event.reason,
    };
  }

  // All other combinations: state unchanged
  return state;
}

// Wrap the transition function with runtime validation using arktype's fn.
// Both parameters and return value are validated against State and Event.
export const transition = type.fn(
  State,
  Event,
  ":",
  State
)(rawTransition);

import { ArkErrors } from "arktype";
import { State, Event } from "./state.js";
import { transition } from "./transition.js";

async function main(): Promise<void> {
  // Read all of stdin
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(Buffer.from(chunk));
  }
  const input = Buffer.concat(chunks).toString("utf-8").trim();

  let parsed: { initial: unknown; events: unknown[] };

  // Parse the JSON input
  try {
    parsed = JSON.parse(input);
  } catch {
    process.stdout.write("INVALID: Failed to parse JSON input\n");
    return;
  }

  if (parsed === null || typeof parsed !== "object") {
    process.stdout.write("INVALID: Input must be a JSON object\n");
    return;
  }

  const doc = parsed as Record<string, unknown>;

  // Validate the initial state
  const initialResult = State(doc.initial);
  if (initialResult instanceof ArkErrors) {
    process.stdout.write(`INVALID: Invalid initial state: ${initialResult.summary}\n`);
    return;
  }

  if (!Array.isArray(doc.events)) {
    process.stdout.write("INVALID: 'events' must be an array\n");
    return;
  }

  let currentState = initialResult;

  // Replay events through transition
  for (let i = 0; i < doc.events.length; i++) {
    const eventResult = Event(doc.events[i]);
    if (eventResult instanceof ArkErrors) {
      process.stdout.write(
        `INVALID: Invalid event at index ${i}: ${eventResult.summary}\n`
      );
      return;
    }

    try {
      currentState = transition(currentState, eventResult);
    } catch (err) {
      // The transition function's runtime validation caught an invalid
      // state produced by the transition logic or an invalid input.
      const message =
        err instanceof ArkErrors
          ? err.summary
          : err instanceof Error
            ? err.message
            : String(err);
      process.stdout.write(
        `INVALID: Transition produced invalid state at event index ${i}: ${message}\n`
      );
      return;
    }
  }

  // Output success
  process.stdout.write("VALID\n");
  process.stdout.write(JSON.stringify(currentState) + "\n");
}

main().catch((err) => {
  process.stdout.write(`INVALID: Unexpected error: ${err instanceof Error ? err.message : String(err)}\n`);
  process.exit(0);
});

